namespace sv_56205d8778fa434dbd38fc2735cb7db7.Models;

public class ApplicationData
{
    // Step 1: Personal Info
    public string Name { get; set; } = string.Empty;
    public string Email { get; set; } = string.Empty;

    // Step 2: Experience
    public List<JobEntry> JobHistory { get; set; } = [];

    // Step 3: References
    public List<ReferenceContact> References { get; set; } = [];

    public HashSet<int> CompletedSteps { get; set; } = [];
}

public class JobEntry
{
    public string Company { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Years { get; set; } = string.Empty;
}

public class ReferenceContact
{
    public string Name { get; set; } = string.Empty;
    public string Email { get; set; } = string.Empty;
    public string Relationship { get; set; } = string.Empty;
}

using System.Collections.Concurrent;
using sv_56205d8778fa434dbd38fc2735cb7db7.Models;

namespace sv_56205d8778fa434dbd38fc2735cb7db7.Services;

/// <summary>
/// Singleton in-memory store for wizard data, keyed by session ID.
/// Both the static layout and interactive pages access this via the
/// session cookie value obtained from HttpContext during SSR/prerender.
/// </summary>
public class WizardStateService
{
    private readonly ConcurrentDictionary<string, ApplicationData> _store = new();

    public ApplicationData GetOrCreate(string sessionKey)
    {
        return _store.GetOrAdd(sessionKey, _ => new ApplicationData());
    }

    public void Remove(string sessionKey)
    {
        _store.TryRemove(sessionKey, out _);
    }
}

@inherits LayoutComponentBase
@inject NavigationManager Nav
@inject IHttpContextAccessor HttpContextAccessor
@inject sv_56205d8778fa434dbd38fc2735cb7db7.Services.WizardStateService WizardState

@{
    var steps = new (string Href, string Label)[]
    {
        ("/apply/personal-info", "Personal Info"),
        ("/apply/experience", "Experience"),
        ("/apply/references", "References"),
        ("/apply/review", "Review"),
    };

    var currentPath = new Uri(Nav.Uri).AbsolutePath.TrimEnd('/');
    int currentStep = Array.FindIndex(steps, s =>
        currentPath.Equals(s.Href, StringComparison.OrdinalIgnoreCase)) + 1;
    if (currentStep == 0) currentStep = 1;

    var sessionKey = HttpContextAccessor.HttpContext?.Request.Cookies["WizardSession"] ?? "";
    var data = string.IsNullOrEmpty(sessionKey) ? null : WizardState.GetOrCreate(sessionKey);
}

<div class="page">
    <div class="sidebar">
        <NavMenu />
    </div>

    <main>
        <div class="top-row px-4">
            <div class="wizard-progress">
                <strong>Step @currentStep of @steps.Length</strong>
                <nav class="wizard-steps">
                    @for (int i = 0; i < steps.Length; i++)
                    {
                        var step = steps[i];
                        int stepNum = i + 1;
                        bool isCurrent = stepNum == currentStep;
                        bool isCompleted = data?.CompletedSteps.Contains(stepNum) == true;
                        string css = isCurrent ? "active" : isCompleted ? "completed" : "";
                        <a href="@step.Href" class="wizard-step @css">
                            <span class="step-number">@stepNum</span>
                            <span class="step-label">@step.Label</span>
                        </a>
                    }
                </nav>
            </div>
        </div>

        <article class="content px-4">
            @Body
        </article>
    </main>
</div>

<div id="blazor-error-ui" data-nosnippet>
    An unhandled error has occurred.
    <a href="." class="reload">Reload</a>
    <span class="dismiss">🗙</span>
</div>

.page {
    position: relative;
    display: flex;
    flex-direction: column;
}

main {
    flex: 1;
}

.sidebar {
    background-image: linear-gradient(180deg, rgb(5, 39, 103) 0%, #3a0647 70%);
}

.top-row {
    background-color: #f7f7f7;
    border-bottom: 1px solid #d6d5d5;
    height: auto;
    display: flex;
    align-items: center;
    padding-top: 0.75rem;
    padding-bottom: 0.75rem;
}

.wizard-progress {
    width: 100%;
    text-align: center;
}

.wizard-steps {
    display: flex;
    gap: 0.5rem;
    margin-top: 0.5rem;
    justify-content: center;
    flex-wrap: wrap;
}

.wizard-step {
    display: flex;
    align-items: center;
    gap: 0.35rem;
    padding: 0.35rem 0.75rem;
    border-radius: 1rem;
    background: #e9ecef;
    color: #495057;
    text-decoration: none;
    font-size: 0.875rem;
    transition: background 0.2s;
}

.wizard-step:hover {
    background: #dee2e6;
    text-decoration: none;
}

.wizard-step.active {
    background: #0d6efd;
    color: white;
    font-weight: 600;
}

.wizard-step.completed {
    background: #198754;
    color: white;
}

.step-number {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: 1.5rem;
    height: 1.5rem;
    border-radius: 50%;
    background: rgba(255, 255, 255, 0.3);
    font-weight: 700;
    font-size: 0.8rem;
}

@media (min-width: 641px) {
    .page {
        flex-direction: row;
    }

    .sidebar {
        width: 250px;
        height: 100vh;
        position: sticky;
        top: 0;
    }

    .top-row {
        position: sticky;
        top: 0;
        z-index: 1;
    }

    .top-row, article {
        padding-left: 2rem !important;
        padding-right: 1.5rem !important;
    }
}

#blazor-error-ui {
    color-scheme: light only;
    background: lightyellow;
    bottom: 0;
    box-shadow: 0 -1px 2px rgba(0, 0, 0, 0.2);
    box-sizing: border-box;
    display: none;
    left: 0;
    padding: 0.6rem 1.25rem 0.7rem 1.25rem;
    position: fixed;
    width: 100%;
    z-index: 1000;
}

    #blazor-error-ui .dismiss {
        cursor: pointer;
        position: absolute;
        right: 0.75rem;
        top: 0.5rem;
    }

