    background-color: #f7f7f7;
    border-bottom: 1px solid #d6d5d5;
    height: auto;
    display: flex;
    align-items: center;
    padding-top: 0.75rem;
    padding-bottom: 0.75rem;
}

.wizard-progress {
    width: 100%;
    text-align: center;
}

.wizard-steps {
    display: flex;
    gap: 0.5rem;
    margin-top: 0.5rem;
    justify-content: center;
    flex-wrap: wrap;
