+@code {
+    private PersonalInfoModel _model = new();
+    private string _sessionKey = string.Empty;
+
+    protected override void OnInitialized()
+    {
+        _sessionKey = EnsureSessionCookie();
+        var data = WizardState.GetOrCreate(_sessionKey);
+        _model.Name = data.Name;
+        _model.Email = data.Email;
+    }
+
+    private void Next()
+    {
+        var data = WizardState.GetOrCreate(_sessionKey);
+        data.Name = _model.Name;
+        data.Email = _model.Email;
+        data.CompletedSteps.Add(1);
+        Nav.NavigateTo("/apply/experience", forceLoad: true);
+    }
+
+    // Reads or creates the session cookie. Available during prerender (SSR).
+    private string EnsureSessionCookie()
+    {
+        var ctx = HttpContextAccessor.HttpContext;
+        if (ctx is null) return string.Empty;
+
+        if (ctx.Request.Cookies.TryGetValue("WizardSession", out var existing) &&
+            !string.IsNullOrEmpty(existing))
+        {
+            return existing;
+        }
+
+        var key = Guid.NewGuid().ToString("N");
+        ctx.Response.Cookies.Append("WizardSession", key, new CookieOptions
+        {
+            HttpOnly = true,
+            SameSite = SameSiteMode.Strict,
+            MaxAge = TimeSpan.FromHours(4)
+        });
+        return key;
+    }
+
+    private class PersonalInfoModel
+    {
+        [System.ComponentModel.DataAnnotations.Required]
+        public string Name { get; set; } = string.Empty;
+
+        [System.ComponentModel.DataAnnotations.Required]
+        [System.ComponentModel.DataAnnotations.EmailAddress]
+        public string Email { get; set; } = string.Empty;
+    }
+}
