@page "/apply/experience"
@layout WizardLayout
@rendermode InteractiveServer
@inject NavigationManager Nav
@inject IHttpContextAccessor HttpContextAccessor
@inject sv_56205d8778fa434dbd38fc2735cb7db7.Services.WizardStateService WizardState
@using sv_56205d8778fa434dbd38fc2735cb7db7.Models

<PageTitle>Apply – Experience</PageTitle>

<h1>Step 2: Work Experience</h1>

@foreach (var (job, index) in _jobs.Select((j, i) => (j, i)))
{
    <div class="card mb-3">
        <div class="card-body">
            <div class="d-flex justify-content-between">
                <h5 class="card-title">Position @(index + 1)</h5>
                <button type="button" class="btn btn-sm btn-outline-danger" @onclick="() => RemoveJob(index)">Remove</button>
            </div>
            <div class="mb-2">
                <label class="form-label">Company</label>
                <input class="form-control" @bind="job.Company" />
            </div>
            <div class="mb-2">
                <label class="form-label">Job Title</label>
                <input class="form-control" @bind="job.Title" />
            </div>
            <div class="mb-2">
                <label class="form-label">Years</label>
                <input class="form-control" @bind="job.Years" placeholder="e.g. 2020–2023" />
            </div>
        </div>
    </div>
}

<button type="button" class="btn btn-outline-secondary mb-3" @onclick="AddJob">+ Add Position</button>

<div class="d-flex justify-content-between">
    <a href="/apply/personal-info" class="btn btn-outline-secondary">← Back</a>
    <button type="button" class="btn btn-primary" @onclick="Next">Next →</button>
</div>

@code {
    private List<JobEntry> _jobs = [];
    private string _sessionKey = string.Empty;

    protected override void OnInitialized()
    {
        _sessionKey = GetSessionKey();
        var data = WizardState.GetOrCreate(_sessionKey);
        // Deep-copy so edits don't mutate the store until user clicks Next
        _jobs = data.JobHistory.Select(j => new JobEntry
        {
            Company = j.Company,
            Title = j.Title,
            Years = j.Years
        }).ToList();

        if (_jobs.Count == 0)
            _jobs.Add(new JobEntry());
    }

    private void AddJob() => _jobs.Add(new JobEntry());

    private void RemoveJob(int index)
    {
        if (_jobs.Count > 0) _jobs.RemoveAt(index);
    }

    private void Next()
    {
        var data = WizardState.GetOrCreate(_sessionKey);
        data.JobHistory = _jobs.Where(j =>
            !string.IsNullOrWhiteSpace(j.Company) ||
            !string.IsNullOrWhiteSpace(j.Title)).ToList();
        data.CompletedSteps.Add(2);
        Nav.NavigateTo("/apply/references", forceLoad: true);
    }

    private string GetSessionKey()
    {
        var ctx = HttpContextAccessor.HttpContext;
        return ctx?.Request.Cookies["WizardSession"] ?? string.Empty;
    }
}

