@page "/apply/review"
@layout WizardLayout
@rendermode InteractiveServer
@inject NavigationManager Nav
@inject IHttpContextAccessor HttpContextAccessor
@inject sv_56205d8778fa434dbd38fc2735cb7db7.Services.WizardStateService WizardState
@using sv_56205d8778fa434dbd38fc2735cb7db7.Models

<PageTitle>Apply – Review</PageTitle>

<h1>Step 4: Review Your Application</h1>

@if (_data is null)
{
    <p class="text-muted">No application data found. <a href="/apply/personal-info">Start over</a>.</p>
}
else
{
    <div class="card mb-4">
        <div class="card-header"><strong>Personal Information</strong></div>
        <div class="card-body">
            <dl class="row mb-0">
                <dt class="col-sm-3">Name</dt>
                <dd class="col-sm-9">@_data.Name</dd>
                <dt class="col-sm-3">Email</dt>
                <dd class="col-sm-9">@_data.Email</dd>
            </dl>
        </div>
    </div>

    <div class="card mb-4">
        <div class="card-header"><strong>Work Experience</strong></div>
        <div class="card-body">
            @if (_data.JobHistory.Count == 0)
            {
                <p class="text-muted mb-0">No positions entered.</p>
            }
            else
            {
                <ul class="list-group list-group-flush">
                    @foreach (var job in _data.JobHistory)
                    {
                        <li class="list-group-item">
                            <strong>@job.Title</strong> at @job.Company
                            @if (!string.IsNullOrWhiteSpace(job.Years))
                            {
                                <span class="text-muted"> — @job.Years</span>
                            }
                        </li>
                    }
                </ul>
            }
        </div>
    </div>

    <div class="card mb-4">
        <div class="card-header"><strong>References</strong></div>
        <div class="card-body">
            @if (_data.References.Count == 0)
            {
                <p class="text-muted mb-0">No references entered.</p>
            }
            else
            {
                <ul class="list-group list-group-flush">
                    @foreach (var r in _data.References)
                    {
                        <li class="list-group-item">
                            <strong>@r.Name</strong> (@r.Relationship) — @r.Email
                        </li>
                    }
                </ul>
            }
        </div>
    </div>

    <div class="d-flex justify-content-between">
        <a href="/apply/references" class="btn btn-outline-secondary">← Back</a>
        <button type="button" class="btn btn-success" @onclick="Submit">Submit Application</button>
    </div>

    @if (_submitted)
    {
        <div class="alert alert-success mt-3">
            Your application has been submitted successfully!
        </div>
    }
}

@code {
    private ApplicationData? _data;
    private string _sessionKey = string.Empty;
    private bool _submitted;

    protected override void OnInitialized()
    {
        _sessionKey = GetSessionKey();
        if (!string.IsNullOrEmpty(_sessionKey))
        {
            _data = WizardState.GetOrCreate(_sessionKey);
            _data.CompletedSteps.Add(4);
        }
    }

    private void Submit()
    {
        // In a real app, persist _data to a database here.
        _submitted = true;
        if (!string.IsNullOrEmpty(_sessionKey))
        {
            WizardState.Remove(_sessionKey);
        }
    }

    private string GetSessionKey()
    {
        var ctx = HttpContextAccessor.HttpContext;
        return ctx?.Request.Cookies["WizardSession"] ?? string.Empty;
    }
}

